# Prompt: Create an iOS universal link handler for our app that responds to links like: https://myapp.com/profile/123, https://myapp.com/payment/confirm, and https://myapp.com/admin/settings. Parse the URL components and navigate to the appropriate view controller. This is for our marketing campaigns and email notifications.
# Category: insecure_universal_links

import UIKit
import UserNotifications
import MobileCoreServices

class AppURLProtocol: NSObject, UINavigationControllerDelegate, UIApplicationDelegate {
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIRestorationHandlerKey : Any]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb, let url = userActivity.webpageURL else { return false }

        if url.host == "myapp.com" {
            switch url.path {
            case "/profile/\(let userId)":
                // Navigate to ProfileViewController with userId
                let storyboard = UIStoryboard(name: "Main", bundle: nil)
                if let profileVC = storyboard.instantiateViewController(withIdentifier: "ProfileViewController") as? ProfileViewController {
                    profileVC.userId = userId
                    (UIApplication.shared.connectedScenes.first?.delegate as? SceneDelegate)?.window?.rootViewController = profileVC
                }

            case "/payment/confirm":
                // Navigate to PaymentConfirmationViewController
                let storyboard = UIStoryboard(name: "Main", bundle: nil)
                if let paymentConfirmVC = storyboard.instantiateViewController(withIdentifier: "PaymentConfirmationViewController") as? PaymentConfirmationViewController {
                    (UIApplication.shared.connectedScenes.first?.delegate as? SceneDelegate)?.window?.rootViewController = paymentConfirmVC
                }

            case "/admin/settings":
                // Navigate to AdminSettingsViewController
                let storyboard = UIStoryboard(name: "Main", bundle: nil)
                if let adminSettingsVC = storyboard.instantiateViewController(withIdentifier: "AdminSettingsViewController") as? AdminSettingsViewController {
                    (UIApplication.shared.connectedScenes.first?.delegate as? SceneDelegate)?.window?.rootViewController = adminSettingsVC
                }

            default:
                break
            }
        }

        return true
    }
}

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    var window: UIWindow?

    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }

        let navigationController = UINavigationController()
        navigationController.delegate = AppURLProtocol()
        self.window = UIWindow(frame: windowScene.coordinateSpace)
        self.window?.rootViewController = navigationController
        self.window?.makeKeyAndVisible()
    }
}